contracts/Scrutin.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./VoteSession.sol";

/**
 * @title Scrutin
 * @dev Manages a single voting event (Scrutin) containing multiple sessions.
 */
contract Scrutin {
    enum Status { Pending, Active, Closed }

    string public title;
    string public description;
    string public scope;
    string public country;
    uint256 public startTime;
    uint256 public endTime;
    Status public status;
    address public owner;

    address[] public sessionAddresses;
    mapping(address => bool) public isSession;

    event SessionAdded(address sessionAddress, string title);
    event ScrutinStatusChanged(Status newStatus);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    constructor(
        string memory _title,
        string memory _description,
        string memory _scope,
        string memory _country,
        uint256 _startTime,
        uint256 _endTime,
        address _owner
    ) {
        title = _title;
        description = _description;
        scope = _scope;
        country = _country;
        startTime = _startTime;
        endTime = _endTime;
        owner = _owner;
        status = Status.Pending;
    }

    function addVoteSession(
        string memory _sessionTitle,
        string memory _sessionDescription,
        uint256 _voterCount,
        address[] memory _moderators
    ) external onlyOwner {
        VoteSession newSession = new VoteSession(
            _sessionTitle,
            _sessionDescription,
            _voterCount,
            _moderators,
            address(this)
        );
        address sessionAddr = address(newSession);
        sessionAddresses.push(sessionAddr);
        isSession[sessionAddr] = true;
        emit SessionAdded(sessionAddr, _sessionTitle);
    }

    function getSessions() external view returns (address[] memory) {
        return sessionAddresses;
    }

    function startScrutin() external onlyOwner {
        require(status == Status.Pending, "Already started or closed");
        status = Status.Active;
        emit ScrutinStatusChanged(status);
    }

    function closeScrutin() external onlyOwner {
        require(status == Status.Active, "Not active");
        status = Status.Closed;
        emit ScrutinStatusChanged(status);
    }
}

contracts/ScrutinFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./Scrutin.sol";

/**
 * @title ScrutinFactory
 * @dev Factory contract to deploy new Scrutin contracts.
 */
contract ScrutinFactory {
    address[] public deployedScrutins;
    address public owner;

    event ScrutinCreated(address scrutinAddress, string title, address owner);

    constructor() {
        owner = msg.sender;
    }

    function createScrutin(
        string memory _title,
        string memory _description,
        string memory _scope,
        string memory _country,
        uint256 _startTime,
        uint256 _endTime
    ) external returns (address) {
        Scrutin newScrutin = new Scrutin(
            _title,
            _description,
            _scope,
            _country,
            _startTime,
            _endTime,
            msg.sender
        );
        address scrutinAddr = address(newScrutin);
        deployedScrutins.push(scrutinAddr);
        emit ScrutinCreated(scrutinAddr, _title, msg.sender);
        return scrutinAddr;
    }

    function getDeployedScrutins() external view returns (address[] memory) {
        return deployedScrutins;
    }
}

contracts/VoteSession.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title VoteSession
 * @dev Manages a single vote session with multiple options (parts).
 */
contract VoteSession {
    struct Option {
        string title;
        uint256 voteCount;
    }

    string public title;
    string public description;
    uint256 public voterCount;
    address public scrutinAddress;
    address[] public moderators;

    Option[] public options;
    mapping(address => bool) public isModerator;
    mapping(bytes32 => bool) public hasVoted; // Hashed email or voter id

    bool public isValidated;
    bool public isInvalidated;
    string public invalidationReason;

    event VoteCast(bytes32 indexed voterHash, uint256 optionIndex);
    event SessionValidated(address moderator);
    event SessionInvalidated(address moderator, string reason);
    event OptionAdded(uint256 index, string title);

    modifier onlyModerator() {
        require(isModerator[msg.sender], "Not moderator");
        _;
    }

    constructor(
        string memory _title,
        string memory _description,
        uint256 _voterCount,
        address[] memory _moderators,
        address _scrutinAddress
    ) {
        title = _title;
        description = _description;
        voterCount = _voterCount;
        scrutinAddress = _scrutinAddress;
        moderators = _moderators;
        for (uint256 i = 0; i < _moderators.length; i++) {
            isModerator[_moderators[i]] = true;
        }
    }

    function addOption(string memory _optionTitle) external {
        // In a real scenario, this might need an owner check
        options.push(Option(_optionTitle, 0));
        emit OptionAdded(options.length - 1, _optionTitle);
    }

    function castVote(bytes32 _voterHash, uint256 _optionIndex) external {
        require(!hasVoted[_voterHash], "Already voted");
        require(_optionIndex < options.length, "Invalid option");

        options[_optionIndex].voteCount++;
        hasVoted[_voterHash] = true;
        emit VoteCast(_voterHash, _optionIndex);
    }

    function validate() external onlyModerator {
        isValidated = true;
        isInvalidated = false;
        emit SessionValidated(msg.sender);
    }

    function invalidate(string memory _reason) external onlyModerator {
        isInvalidated = true;
        isValidated = false;
        invalidationReason = _reason;
        emit SessionInvalidated(msg.sender, _reason);
    }

    function getOptions() external view returns (Option[] memory) {
        return options;
    }

    function getOptionCount() external view returns (uint256) {
        return options.length;
    }
}

